vector<int> ask(int k){
	cout << "? " << k << endl;
	int l;
	cin >> l;
	if (l == -1){
		exit(0);
	}
	vector<int> res(l);
	for (int i = 0; i < l; i++){
		cin >> res[i];
	}
	return res;
}

void solve(){
	int n;
	cin >> n;

	vector<pair<int, int>> edges;

	for (int i = 0; i < n; i++){
		int prev = -1;
		while(1){
			int l = 1, r = (1 << 30);
			while(l <= r){
				int m = l + (r - l) / 2;
				auto path = ask(m);
				if (!path.empty() && path[0] < i + 1){
					l = m + 1;
					continue;
				}
				if (path.empty() || path[0] > i + 1 || (path.size() > 1 && path[1] > prev)){
					r = m - 1;
				}
				else{
					l = m + 1;
				}
			}

			auto path = ask(l);
			if (path.size() > 1){
				edges.emplace_back(path[0], path[1]);
				prev = path[1];
			}
			else{
				break;
			}
		}
	}

	cout << "! " << edges.size() << endl;
	for (auto [u, v] : edges){
		cout << u << '
' << v << endl;
	}
}

signed main()
{
#ifdef FELIX
	auto _clock_start = chrono::high_resolution_clock::now();
#endif
	ios_base::sync_with_stdio(false);
	cin.tie(0);
	cout.tie(0);

	int t = 1;
	cin >> t;
	while(t--){
		solve();
	}

#ifdef FELIX
	cerr << "Executed in " << chrono::duration_cast<chrono::milliseconds>(
		chrono::high_resolution_clock::now()
			- _clock_start).count() << "ms." << endl;
#endif
	return 0;
}
